// Cambiar startDate al primer día del mes a cargar. endDate = último día.
// Ejemplos:
//   Enero 2025: '2025-01-01', '2025-01-31'
//   Febrero 2025: '2025-02-01', '2025-02-28'
//   ...
return [{ json: { startDate: '2025-01-01', endDate: '2025-01-31' } }];

// La respuesta de runReport viene en $json.rows[0].metricValues
const resp = $input.first().json;
const config = $('Set Config (month)').first().json;
const metricValues = resp?.rows?.[0]?.metricValues ?? [];
const toInt = (v) => {
  const n = Number(v?.value ?? 0);
  return Number.isFinite(n) ? Math.round(n) : 0;
};
return [{
  json: {
    mes: config.startDate,
    total_users: toInt(metricValues[0]),
    new_users: toInt(metricValues[1]),
    sesiones: toInt(metricValues[2]),
    pageviews: toInt(metricValues[3]),
  },
}];
